'use client'
import { cn } from '@cascivo/core'
import type { HTMLAttributes } from 'react'
import styles from './blockquote.module.css'

export interface BlockquoteProps extends HTMLAttributes<HTMLQuoteElement> {
  cite?: string
}

export function Blockquote({ cite, className, children, ...props }: BlockquoteProps) {
  return (
    <blockquote className={cn(styles['blockquote'], className as string | undefined)} {...props}>
      {children}
      {cite ? (
        <footer className={styles['footer']}>
          <cite>{cite}</cite>
        </footer>
      ) : null}
    </blockquote>
  )
}

@layer cascivo.component {
  .blockquote {
    margin: 0;
    border-inline-start: 3px solid var(--cascivo-color-border-strong);
    padding-inline-start: var(--cascivo-space-4);
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-base);
    line-height: var(--cascivo-leading-relaxed);
    color: var(--cascivo-color-text-subtle);
  }

  .footer {
    margin-block-start: var(--cascivo-space-2);
    font-size: var(--cascivo-text-sm);

    & cite {
      font-style: normal;
      color: var(--cascivo-color-text);
      font-weight: var(--cascivo-font-medium);

      &::before {
        content: '— ';
      }
    }
  }
}
